import{_ as o,o as d,c,a2 as i}from"./chunks/framework.CE5oItKu.js";const m=JSON.parse('{"title":"后端命名规范","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/backend/02-naming.md","filePath":"mango-pmo/rules/backend/02-naming.md"}'),a={name:"mango-pmo/rules/backend/02-naming.md"};function l(r,e,t,n,s,u){return d(),c("div",null,[...e[0]||(e[0]=[i('<h1 id="后端命名规范" tabindex="-1">后端命名规范 <a class="header-anchor" href="#后端命名规范" aria-label="Permalink to &quot;后端命名规范&quot;">​</a></h1><h2 id="_1-基本规则" tabindex="-1">1. 基本规则 <a class="header-anchor" href="#_1-基本规则" aria-label="Permalink to &quot;1. 基本规则&quot;">​</a></h2><ul><li>模块名使用 <code>kebab-case</code>。</li><li>包名使用小写。</li><li>类名使用 <code>PascalCase</code>。</li><li>方法和变量使用 <code>camelCase</code>。</li><li>表名和字段名使用小写下划线。</li></ul><h2 id="_2-统一后缀" tabindex="-1">2. 统一后缀 <a class="header-anchor" href="#_2-统一后缀" aria-label="Permalink to &quot;2. 统一后缀&quot;">​</a></h2><ul><li>持久化实体：<code>XxxEntity</code></li><li>新增入参：<code>CreateXxxCommand</code></li><li>更新入参：<code>UpdateXxxCommand</code></li><li>查询入参：<code>XxxQuery</code></li><li>分页查询：<code>XxxPageQuery</code></li><li>返回对象：<code>XxxVO</code></li><li>对外接口：<code>XxxApi</code></li><li>内部服务：<code>IXxxService</code></li><li>对外接口实现：<code>XxxController</code>、<code>XxxFeignClient</code></li><li>内部服务实现：<code>XxxService</code></li><li>扩展接口：<code>I...Provider</code>、<code>I...Checker</code>、<code>I...Validator</code></li></ul><h2 id="_3-禁止后缀" tabindex="-1">3. 禁止后缀 <a class="header-anchor" href="#_3-禁止后缀" aria-label="Permalink to &quot;3. 禁止后缀&quot;">​</a></h2><ul><li><code>PO</code></li><li><code>DO</code></li><li><code>DTO</code> 作为仓内业务 API 入参或返回命名</li></ul><h2 id="_4-包规则" tabindex="-1">4. 包规则 <a class="header-anchor" href="#_4-包规则" aria-label="Permalink to &quot;4. 包规则&quot;">​</a></h2><ul><li><code>api</code> 只放 <code>command</code>、<code>query</code>、<code>vo</code>、<code>enums</code>、<code>XxxApi</code>。</li><li><code>core</code> 只放 <code>entity</code>、<code>service</code>、<code>mapper</code>、<code>convert</code>。</li><li>不新增语义不清的 <code>model</code>、<code>dto</code>、<code>po</code>、<code>util</code>、<code>helper</code> 杂项包。</li></ul><h2 id="_5-领域词规则" tabindex="-1">5. 领域词规则 <a class="header-anchor" href="#_5-领域词规则" aria-label="Permalink to &quot;5. 领域词规则&quot;">​</a></h2><ul><li>同一业务概念在模块、包、类、表中使用同一领域词。</li><li>不允许同一模块出现多套命名。</li><li><code>XxxApi</code> 名称只表达跨模块能力，不使用 <code>Registry</code>、<code>Dispatcher</code>、<code>Manager</code>、<code>Session</code> 等内部实现词。</li><li>历史命名迁移后不保留第二套新实现。</li></ul><h2 id="_6-kv-key-规则" tabindex="-1">6. KV Key 规则 <a class="header-anchor" href="#_6-kv-key-规则" aria-label="Permalink to &quot;6. KV Key 规则&quot;">​</a></h2><ul><li>Redis/KV key 统一由 <code>mango-infra-kv</code> capability 层增加基础设施前缀。</li><li>默认格式：<code>mango:kv:{env}:{capability}:{biz-key}</code>。</li><li>可选应用隔离格式：<code>mango:kv:{env}:{app}:{capability}:{biz-key}</code>。</li><li>默认不加应用名，保证同一环境内 infra KV 可跨应用共享。</li><li>环境段用于隔离 dev/test/prod。</li><li>能力段固定为：<code>cache</code>、<code>lock</code>、<code>counter</code>、<code>rate-limit</code>、<code>idempotent</code>、<code>token</code>、<code>idgen</code>。</li><li>业务代码只传业务段 key，例如 <code>user:#{#userId}</code>。</li><li>KV 注解动态 key 必须使用 SpEL 模板或直接 SpEL 表达式。</li><li>禁止业务代码手写 <code>mango:kv</code> 完整前缀。</li><li>禁止 <code>user:#userId</code>、<code>user:@bean</code> 这类非标准内联占位写法。</li></ul><h2 id="_7-禁止事项" tabindex="-1">7. 禁止事项 <a class="header-anchor" href="#_7-禁止事项" aria-label="Permalink to &quot;7. 禁止事项&quot;">​</a></h2><ul><li>混用多种命名风格</li><li>使用无语义缩写</li><li>用 <code>data</code>、<code>info</code>、<code>temp</code>、<code>obj</code> 这类泛化命名</li></ul>',15)])])}const x=o(a,[["render",l]]);export{m as __pageData,x as default};
